import { useState } from 'react';
import { Briefcase, BookOpen, Landmark, FlameKindling, Globe, Building2, GraduationCap, Award, ExternalLink } from 'lucide-react';
import SectionHeader from './SectionHeader';
import GlassCard from './GlassCard';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';
import { ink, muted, faint } from '../utils/glass';

function getIcon(org, type) {
  if (org.includes('CIB') || org.includes('التجاري')) return Landmark;
  if (org.includes('ASORC') || org.includes('Refin') || org.includes('تكرير')) return FlameKindling;
  if (org.includes('Nile') || org.includes('النيل')) return FlameKindling;
  if (org.includes('Google') || org.includes('Misr')  || org.includes('مصر')) return Globe;
  if (org.includes('HSBC')) return Building2;
  return type === 'internship' ? Briefcase : GraduationCap;
}

function accent(type) {
  return type === 'internship'
    ? { color:'#f0a500', bg:'rgba(240,165,0,0.12)', border:'rgba(240,165,0,0.28)', glow:'rgba(240,165,0,0.22)', stripe:'linear-gradient(90deg,#f0a500,#e8920a)' }
    : { color:'#2a9d8f', bg:'rgba(42,157,143,0.12)', border:'rgba(42,157,143,0.28)', glow:'rgba(42,157,143,0.22)', stripe:'linear-gradient(90deg,#2a9d8f,#1f7a6e)' };
}

function Topics({ desc, dark }) {
  if (!desc || !desc.includes('·')) return <p className="text-[.85rem] leading-[1.75]" style={{ color:muted(dark) }}>{desc}</p>;
  return (
    <div className="flex flex-wrap gap-1.5">
      {desc.split('·').map((item, i) => (
        <span key={i} className="text-[.72rem] px-2.5 py-1 rounded-lg font-medium"
          style={{ background:dark?'rgba(255,255,255,0.07)':'rgba(26,26,46,0.06)', border:`1px solid ${dark?'rgba(255,255,255,0.12)':'rgba(26,26,46,0.10)'}`, color:muted(dark) }}>
          {item.trim()}
        </span>
      ))}
    </div>
  );
}

export default function Experience() {
  const { dark, lang } = useApp();
  const tr = t[lang];
  const [filter, setFilter] = useState('all');
  const bg = dark ? '#0f0f14' : '#fdfcf9';

  const all  = tr.experiences;
  const intr = all.filter(e => e.type==='internship');
  const trai = all.filter(e => e.type==='training');
  const shown = filter==='all' ? all : filter==='internship' ? intr : trai;

  const fActiveStyle   = { background:dark?'#f0f0f8':'#1a1a2e', color:dark?'#0f0f14':'#fdfcf9', border:'1px solid transparent' };
  const fInactiveStyle = { background:dark?'rgba(255,255,255,0.06)':'rgba(255,255,255,0.75)', border:`1px solid ${dark?'rgba(255,255,255,0.14)':'rgba(26,26,46,0.14)'}`, color:muted(dark), backdropFilter:'blur(12px)' };

  return (
    <section id="experience" style={{ background:bg }} className="py-24 px-[5%] transition-colors duration-300">
      <SectionHeader tag={tr.expTag} title={tr.expTitle} />

      {/* Filter tabs */}
      <div className="flex gap-2 mb-10 flex-wrap">
        {[['all',tr.all,all.length],['internship',tr.internships,intr.length],['training',tr.training,trai.length]].map(([v,l,c]) => (
          <button key={v} onClick={() => setFilter(v)}
            className="px-4 py-1.5 rounded-full text-sm font-medium transition-all"
            style={filter===v ? fActiveStyle : fInactiveStyle}>
            {l} <span className="opacity-50 text-xs ml-1">({c})</span>
          </button>
        ))}
      </div>

      <div className="grid md:grid-cols-2 gap-4">
        {shown.map((e, i) => {
          const acc  = accent(e.type);
          const Icon = getIcon(e.org, e.type);
          return (
            <GlassCard key={`${filter}-${i}`} dark={dark} glow={acc.glow}
              className="reveal rounded-2xl overflow-visible"
              style={{ transitionDelay:`${i*0.07}s` }}>

              {/* Accent stripe top */}
              <div className="h-[3px] w-full" style={{ background:acc.stripe }} />

              <div className="p-5">
                <div className="flex items-start gap-3">
                  {/* Icon */}
                  <div className="w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0"
                    style={{ background:acc.bg, border:`1px solid ${acc.border}`, color:acc.color }}>
                    <Icon size={18}/>
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1 flex-wrap">
                      <span className="inline-flex items-center gap-1 text-[.6rem] font-semibold tracking-wider uppercase px-2 py-0.5 rounded-full"
                        style={{ background:acc.bg, border:`1px solid ${acc.border}`, color:acc.color }}>
                        {e.type==='internship' ? <><Briefcase size={9}/>{lang==='ar'?'تدريب':'Internship'}</> : <><BookOpen size={9}/>{lang==='ar'?'كورس':'Training'}</>}
                      </span>
                      <span className="text-[.65rem] font-medium" style={{ color:faint(dark) }}>{e.date}</span>
                    </div>
                    <h3 className="font-semibold text-[.95rem] leading-tight" style={{ color:ink(dark) }}>{e.role}</h3>
                    <p className="text-[.78rem] mt-0.5" style={{ color:muted(dark) }}>{e.org} · {e.location}</p>
                  </div>
                </div>

                <div className="mt-3 pt-3" style={{ borderTop:`1px solid ${dark?'rgba(255,255,255,0.08)':'rgba(26,26,46,0.08)'}` }}>
                  <Topics desc={e.desc} dark={dark}/>
                </div>

                {e.certImg && (
                  <a href={e.certImg} target="_blank" rel="noreferrer"
                    className="inline-flex items-center gap-1.5 mt-3 text-[.72rem] font-medium transition-colors hover:opacity-80"
                    style={{ color:acc.color }}>
                    <Award size={12}/>{lang==='ar'?'عرض الشهادة':'View Certificate'}<ExternalLink size={10}/>
                  </a>
                )}
              </div>
            </GlassCard>
          );
        })}
      </div>
    </section>
  );
}
